import{_ as t,o as r,c as a,a7 as n}from"./chunks/framework.C5fSpjcB.js";const m=JSON.parse('{"title":"Currency","description":"","frontmatter":{},"headers":[],"relativePath":"en/items/currency.md","filePath":"en/items/currency.md","lastUpdated":1775394001000}'),i={name:"en/items/currency.md"};function s(o,e,d,l,c,h){return r(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="currency" tabindex="-1">Currency <a class="header-anchor" href="#currency" aria-label="Permalink to &quot;Currency&quot;">​</a></h1><p>Morimens features several types of in-game currency used for summoning, purchasing items, and upgrading.</p><h2 id="premium-currencies" tabindex="-1">Premium Currencies <a class="header-anchor" href="#premium-currencies" aria-label="Permalink to &quot;Premium Currencies&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Currency</th><th>Usage</th><th>How to Obtain</th></tr></thead><tbody><tr><td>Silver Prime</td><td>Paid premium currency. Used to purchase summon items, battle pass, cosmetics, and gift boxes.</td><td>Real-money purchase</td></tr><tr><td>Silver (Silver Core)</td><td>Primary free premium currency. Exchange for Luminous Core or Pure Core in the shop. Can also restore Menophine (50 Silver = 120 Menophine).</td><td>Daily tasks, main story scores, main story achievements, handbook, Phantasmal Dive, events, battle pass, redemption codes, map exploration</td></tr></tbody></table><h2 id="summoning-currencies" tabindex="-1">Summoning Currencies <a class="header-anchor" href="#summoning-currencies" aria-label="Permalink to &quot;Summoning Currencies&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Currency</th><th>Usage</th><th>How to Obtain</th></tr></thead><tbody><tr><td>Luminous Core</td><td>Limited banner summon item. Used for limited character and Wheel of Destiny banners. Priority exchange recommended.</td><td>Silver exchange, events, battle pass</td></tr><tr><td>Pure Core</td><td>Standard banner summon item. Used for standard character and Wheel of Destiny banners. More sources available than Luminous Core.</td><td>Silver exchange, events, first Awakener ascension reward, battle pass free track (40x), chapter first clear</td></tr></tbody></table><h2 id="exchange-currencies" tabindex="-1">Exchange Currencies <a class="header-anchor" href="#exchange-currencies" aria-label="Permalink to &quot;Exchange Currencies&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Currency</th><th>Usage</th><th>How to Obtain</th></tr></thead><tbody><tr><td>Rose Scrip</td><td>Main general currency. Used in Rose Scrip Shop, edification, alchemy, material synthesis, wheel stacking, covenant transcription (7,500/attempt).</td><td>Main story first clear, Dissolution Ruins, Outfield Agent, Curriculum, wheel disassembly (Blue=1,000, Purple=4,000)</td></tr><tr><td>Sediment Currency</td><td>Used in Sediment Shop. Purchase covenant sets (Scarlet Embrace), Memory Quill (80 sediment = 10 quills/week), Primordial Spirit Core (25 shards = 1 core, 3x/month).</td><td>Summoning (gacha byproduct)</td></tr><tr><td>Investigation Badge</td><td>Used in Investigation Shop. Purchase Memory Quill (800 badges = 5 quills/week).</td><td>Main story 3-star clear, Arcane Dominion, Soul Dive 3-star, True Mastery (1,000), personal achievements (300 each)</td></tr><tr><td>Lightless Currency</td><td>Used in Lightless Shop. Purchase covenant sets (Distant Feast), Memory Quill (800 = 5/week).</td><td>Lightless Realm, D-Effect Zone</td></tr><tr><td>D-Jewels (Erosion Pearls)</td><td>Used in Deep Dive Shop. Purchase Memory Quill (800 = 5/week), Shattered Remnant Dream (100/week), Stellar Remnant Dream (25/week). Formula: (Phantasmal level + 2) x 100.</td><td>Phantasmal Dive (Level 3 = 500, Frenzy = 900), Outfield Agent (daily settlement)</td></tr><tr><td>Phase Coin</td><td>Used in Phase Shop. Purchase covenant sets (Scarlet Palpitation), Memory Quill (800 = 5/week).</td><td>Phase Chess (PVP)</td></tr></tbody></table><h2 id="stamina" tabindex="-1">Stamina <a class="header-anchor" href="#stamina" aria-label="Permalink to &quot;Stamina&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Currency</th><th>Usage</th><th>How to Obtain</th></tr></thead><tbody><tr><td>Menophine</td><td>Stamina/action resource consumed when entering intermission drills. 50 Silver = 120 Menophine.</td><td>Natural recovery, Silver exchange, items/gift boxes</td></tr></tbody></table><h2 id="currency-spending-advice" tabindex="-1">Currency Spending Advice <a class="header-anchor" href="#currency-spending-advice" aria-label="Permalink to &quot;Currency Spending Advice&quot;">​</a></h2><ol><li><strong>Save premium currency for limited banners</strong> -- Do not spend on the standard banner unless you have surplus.</li><li><strong>Prioritize Luminous Core</strong> -- When exchanging Silver, Luminous Core should be prioritized over Pure Core since limited banner characters are time-restricted.</li><li><strong>Buy stamina refreshes wisely</strong> -- The first few daily stamina refreshes are cost-efficient; later ones are not.</li><li><strong>Clear event shops</strong> -- Event currency expires when the event ends. Spend it before the deadline.</li><li><strong>Prioritize summoning resources</strong> -- In most shops, summon tickets and pulls offer the best long-term value.</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Premium currency spent on the standard banner is generally less efficient than saving for a limited banner with a specific Awakener you want.</p></div><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./">Items Overview</a></li><li><a href="./../modes/gacha.html">Gacha / Summoning</a></li><li><a href="./materials.html">Materials</a></li></ul>',15)])])}const p=t(i,[["render",s]]);export{m as __pageData,p as default};
